import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Context Cards","description":"","frontmatter":{},"headers":[],"relativePath":"guide/context-cards.md","filePath":"guide/context-cards.md","lastUpdated":1773993597000}'),n={name:"guide/context-cards.md"};function r(s,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="context-cards" tabindex="-1">Context Cards <a class="header-anchor" href="#context-cards" aria-label="Permalink to &quot;Context Cards&quot;">​</a></h1><p>Context cards are the nine lifestyle panels on your dashboard, grouped under the heading <strong>&quot;What your GP won&#39;t ask you.&quot;</strong> They capture the health context that shapes your lab results — information a typical appointment rarely has time to explore.</p><h2 id="what-they-are" tabindex="-1">What They Are <a class="header-anchor" href="#what-they-are" aria-label="Permalink to &quot;What They Are&quot;">​</a></h2><p>Each card represents a different area of your life that influences your biomarkers. The dashboard shows a summary of every card at a glance, along with a count of how many you have filled in (e.g., <strong>5/9 filled</strong>).</p><p>The nine cards, in order:</p><ol><li><strong>Health Goals</strong> — what you are working toward</li><li><strong>Medical Conditions</strong> — diagnoses and ongoing conditions</li><li><strong>Diet</strong> — eating patterns, meal timing, and restrictions</li><li><strong>Exercise</strong> — frequency, types, intensity, and daily movement</li><li><strong>Sleep &amp; Rest</strong> — duration, quality, sleep environment, and practices</li><li><strong>Light &amp; Circadian</strong> — morning light, UV exposure, evening screen habits, and grounding</li><li><strong>Stress</strong> — stress level, sources, and management strategies</li><li><strong>Love Life &amp; Relationships</strong> — relationship quality and sexual health</li><li><strong>Environment</strong> — water quality, EMF exposure, air quality, and toxin sources</li></ol><h2 id="ai-health-dots-and-tips" tabindex="-1">AI Health Dots and Tips <a class="header-anchor" href="#ai-health-dots-and-tips" aria-label="Permalink to &quot;AI Health Dots and Tips&quot;">​</a></h2><p>Each card displays a small colored dot in its corner:</p><ul><li><strong>Green</strong> — this area looks supportive of your health</li><li><strong>Yellow</strong> — there may be something worth paying attention to here</li><li><strong>Red</strong> — this area may be contributing to out-of-range results</li><li><strong>Gray</strong> — not enough information to assess</li></ul><p>Below the dot, you will see a brief AI-generated tip (up to 12 words) tailored to your data. These dots and tips are cached and only refreshed when your data or card content changes.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Fill in as many cards as you can. The AI uses all of this context when interpreting your lab results in chat and in the Focus Card.</p></div><h2 id="opening-a-card-editor" tabindex="-1">Opening a Card Editor <a class="header-anchor" href="#opening-a-card-editor" aria-label="Permalink to &quot;Opening a Card Editor&quot;">​</a></h2><p>Click any card to open its editor modal. Each editor uses pill-button selectors and tag pills for multi-select options — no dropdowns to dig through. Changes save when you click <strong>Save</strong>.</p><h2 id="circadian-mitochondrial-health-options" tabindex="-1">Circadian &amp; Mitochondrial Health Options <a class="header-anchor" href="#circadian-mitochondrial-health-options" aria-label="Permalink to &quot;Circadian &amp; Mitochondrial Health Options&quot;">​</a></h2><p>Several cards include options inspired by circadian biology and mitochondrial health frameworks:</p><p><strong>Sleep &amp; Rest</strong> includes:</p><ul><li>Room temperature setting</li><li>Sleep environment options: blackout curtains, low-EMF setup, grounding sheet, Magnetico sleep pad</li><li>Sleep practices: mouth taping, cold shower before bed, magnesium</li></ul><p><strong>Light &amp; Circadian</strong> includes:</p><ul><li>Morning sunlight exposure (AM light)</li><li>UV exposure habits</li><li>Evening discipline (no artificial light, blue-light glasses, etc.)</li><li>Cold exposure and grounding/earthing</li><li>Screen time and technology environment</li><li>Meal timing relative to light cycles</li></ul><p>Your location (set in Settings) is used to auto-detect your latitude band, which appears in the Light &amp; Circadian card context sent to the AI.</p><p><strong>Environment</strong> includes:</p><ul><li>Water quality: spring water, deuterium-depleted water (DDW), reverse osmosis</li><li>EMF sources and mitigation strategies</li><li>Home lighting type</li><li>Air quality and toxin exposure</li><li>Building materials</li></ul><h3 id="emf-assessment" tabindex="-1">EMF Assessment <a class="header-anchor" href="#emf-assessment" aria-label="Permalink to &quot;EMF Assessment&quot;">​</a></h3><p>The Environment card includes a dedicated <strong>Baubiologie EMF Assessment</strong> sub-module for tracking electromagnetic field measurements room by room. Open the Environment card editor and click <strong>Open EMF Assessment</strong> to access it.</p><p>Features:</p><ul><li><strong>Room-by-room measurements</strong> — bedroom, office, living room, or custom rooms. Each room can be marked as a sleeping or daytime area, which changes the severity thresholds</li><li><strong>SBM-2015 severity grading</strong> — measurements are rated against Building Biology (Baubiologie) standards across 5 types: AC electric fields (V/m), AC magnetic fields (nT), RF/microwave radiation (µW/m²), dirty electricity (GS), and DC magnetic deviation (µT). Severity ranges from No Concern (green) to Extreme Concern (red), with separate thresholds for sleeping and daytime areas</li><li><strong>Meter presets</strong> — autocomplete suggestions for common EMF meters (e.g., Gigahertz NFA1000, Safe and Sound Pro II)</li><li><strong>Sources and mitigations</strong> — tag common EMF sources (WiFi router, smart meter, cell tower) and mitigation steps (demand switch, shielding paint, WiFi off at night) per room</li><li><strong>Room photos</strong> — attach up to 6 photos per room to document meter readings or setup</li><li><strong>PDF import</strong> — import professional consultant reports via AI-powered PDF extraction</li><li><strong>AI interpretation</strong> — generate a streaming AI analysis of a single assessment, or compare two assessments (before vs after remediation) with color-coded delta arrows</li><li><strong>Printable template</strong> — download a blank assessment form for on-site use</li></ul><p>EMF data is included in the AI chat context and JSON export/import.</p><p><strong>Diet &amp; Digestion</strong> includes:</p><ul><li>Eating patterns, meal timing, and dietary restrictions</li><li>10 digestion fields: bowel frequency, stool consistency, bloating, gas, acid reflux, burping, nausea, appetite, abdominal pain, and food sensitivities</li></ul><h2 id="additional-notes" tabindex="-1">Additional Notes <a class="header-anchor" href="#additional-notes" aria-label="Permalink to &quot;Additional Notes&quot;">​</a></h2><p>Below the card grid is a free-form <strong>Additional Notes</strong> textarea. Use this to add anything that does not fit neatly into a structured card — recent travel, a new medication, unusual stress, anything relevant. This text is auto-saved and included in every AI conversation.</p><h2 id="how-context-reaches-the-ai" tabindex="-1">How Context Reaches the AI <a class="header-anchor" href="#how-context-reaches-the-ai" aria-label="Permalink to &quot;How Context Reaches the AI&quot;">​</a></h2><p>When you chat with the AI or view the Focus Card, all nine cards plus the Additional Notes textarea are included in the context sent to the AI. The AI uses this to give you interpretations that go beyond the numbers — it can flag when your sleep schedule, diet, or environment might explain a result, or suggest that a pattern in your labs aligns with something you mentioned in a card.</p><h2 id="change-history" tabindex="-1">Change History <a class="header-anchor" href="#change-history" aria-label="Permalink to &quot;Change History&quot;">​</a></h2><p>getbased automatically timestamps every change you make to a context card. When you switch from Mediterranean to carnivore diet, or change your stress level from high to moderate, the previous value and the date of the change are recorded.</p><p>This timeline is included in the AI context so the AI can reason about temporal correlations — for example, connecting a dietary change on March 1 to a shift in your LDL two weeks later. You do not need to do anything to enable this; it works automatically whenever you save a card.</p><p>Change history is included in <a href="/docs/guide/json-export-import.html">JSON export and import</a>.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Context cards never leave your device except as part of AI API calls (to your chosen provider). See <a href="/docs/guide/ai-providers.html">AI Providers</a> and <a href="/docs/guide/encryption.html">Encryption</a> for details on how your data is handled.</p></div>',38)])])}const p=t(n,[["render",r]]);export{u as __pageData,p as default};
